export function buildContentGenerationSystemPrompt(
  companyName: string
): string {
  return `You are a senior content strategist and multi-platform creator for ${companyName}.

You create high-quality, on-brand content packages optimized for each platform's format and audience.

You MUST return valid JSON only. No markdown fences.

Be strategic, specific, and actionable. Every piece of content must feel native to its platform.`;
}

export function buildContentGenerationUserPrompt(
  contextBlock: string,
  topic: string,
  platforms: SocialPlatform[]
): string {
  const platformSchemas = platforms
    .map((p) => PLATFORM_SCHEMA_HINTS[p])
    .join(",\n    ");

  const platformList = platforms.map((p) => getPlatformLabel(p)).join(", ");

  return `BRAND CONTEXT:
${contextBlock}

TOPIC / NEWS / IDEA:
${topic}

PLATFORMS TO GENERATE (only include these keys in content object):
${platformList}

Return a JSON object with EXACTLY this structure:
{
  "strategyNote": "2-4 sentences explaining your content angle for this topic",
  "agentReasoning": "Why this approach will work for this brand and topic right now",
  "content": {
    ${platformSchemas}
  }
}

CRITICAL RULES:
- Only include platform keys listed above inside "content"
- youtube_short script must be 60-90 seconds when read aloud (~150-225 words in body)
- youtube description must include timestamp markers (0:00 Hook, etc.) and a CTA with website if available
- image/thumbnail prompts MUST name the company, specify exact brand colors from Visual Style, and describe how the logo/wordmark appears
- image prompts must visually support the post/script content — not generic stock imagery
- x posts should stay under 280 characters for POST format
- linkedin should be professional but not corporate-boring
- All hashtags without # symbol in the array
- Return ONLY the JSON object`;
}

import type { AIProvider, BusinessProfile } from '@/lib/agent/types'
import { buildBusinessContextBlock } from '@/lib/agent/context'
import { callAI } from '@/lib/ai/call-ai'
import { safeParseJsonResponse } from '@/lib/ai/parse-response'

export interface TopicSuggestion {
  topic: string
  angle: string
  whyNow: string
}

export interface RecommendTopicsResult {
  suggestions: TopicSuggestion[]
  model: string
}

export async function recommendTopics(params: {
  provider: AIProvider
  business: BusinessProfile
  count?: number
}): Promise<RecommendTopicsResult> {
  const { provider, business, count = 5 } = params
  const context = buildBusinessContextBlock(business)

  const result = await callAI({
    provider,
    purpose: 'recommend_topics',
    temperature: 0.75,
    jsonMode: true,
    maxTokens: 2048,
    messages: [
      {
        role: 'system',
        content: `You are a senior content strategist. Suggest timely, high-engagement topics for social media content.
Return valid JSON only.`,
      },
      {
        role: 'user',
        content: `${context}

Suggest exactly ${count} content topics this brand should post about in the next 1–2 weeks.

Each topic should be:
- Specific enough to generate a full content package (not vague like "marketing tips")
- Aligned with brand voice, audience, and goals
- Timely or evergreen with a fresh angle

Return JSON:
{
  "suggestions": [
    {
      "topic": "One clear sentence describing what to post about (this becomes the generation prompt)",
      "angle": "Short hook angle in 5-12 words",
      "whyNow": "One sentence on why this works for this brand right now"
    }
  ]
}`,
      },
    ],
  })

  const parsed = safeParseJsonResponse<{ suggestions?: TopicSuggestion[] }>(result.content)
  const raw = parsed?.suggestions ?? []

  const suggestions = raw
    .filter((s) => s?.topic?.trim())
    .slice(0, count)
    .map((s) => ({
      topic: String(s.topic).trim(),
      angle: String(s.angle || '').trim() || 'Fresh angle for your audience',
      whyNow: String(s.whyNow || '').trim() || 'Aligned with your brand goals',
    }))

  if (suggestions.length === 0) {
    throw new Error('Could not generate topic suggestions')
  }

  return { suggestions, model: result.model }
}

import type {
  AIProvider,
  BusinessProfile,
  ContentEpisodePayload,
  PlatformContent,
  SocialPlatform,
} from "@/lib/agent/types";
import { buildBusinessContextBlock } from "@/lib/agent/context";
import { sanitizeEpisodePayload } from "@/lib/agent/sanitize-episode";
import { getPlatformLabel } from "@/lib/constants/platforms";
import { callAI } from "@/lib/ai/call-ai";
import { safeParseJsonResponse } from "@/lib/ai/parse-response";

export interface RegenerateEpisodeParams {
  provider: AIProvider;
  business: BusinessProfile;
  topic: string;
  platform: SocialPlatform;
  currentPayload: ContentEpisodePayload;
  feedback: string;
}

export interface RegenerateEpisodeResult {
  payload: ContentEpisodePayload;
  model: string;
  usage: Awaited<ReturnType<typeof callAI>>["usage"];
}

export async function regenerateEpisodeSection(
  params: RegenerateEpisodeParams
): Promise<RegenerateEpisodeResult> {
  const {
    provider,
    business,
    topic,
    platform,
    currentPayload,
    feedback,
  } = params;

  const contextBlock = buildBusinessContextBlock(business);
  const platformLabel = getPlatformLabel(platform);
  const currentContent = currentPayload.content[platform];

  const systemPrompt = `You are a senior content strategist for ${business.name}.
You are regenerating content for ${platformLabel} based on human feedback.
Return valid JSON only.`;

  const userPrompt = `BRAND CONTEXT:
${contextBlock}

TOPIC: ${topic}

CURRENT ${platformLabel.toUpperCase()} CONTENT:
${JSON.stringify(currentContent, null, 2)}

HUMAN FEEDBACK:
"${feedback}"

Return a JSON object with EXACTLY this structure:
{
  "agentReasoning": "Explain what you changed and why based on the feedback",
  "content": {
    "${platform}": { ... regenerated content for this platform only ... }
  }
}

Only include the "${platform}" key inside content. Improve the content based on feedback while staying on-brand.`;

  const result = await callAI({
    provider,
    purpose: "regenerate_episode",
    temperature: 0.7,
    jsonMode: true,
    maxTokens: 4096,
    messages: [
      { role: "system", content: systemPrompt },
      { role: "user", content: userPrompt },
    ],
  });

  const parsed = safeParseJsonResponse<{
    agentReasoning?: string;
    content?: PlatformContent;
  }>(result.content);

  if (!parsed?.content?.[platform]) {
    throw new Error("Failed to parse regeneration response");
  }

  const mergedContent: PlatformContent = {
    ...currentPayload.content,
    [platform]: parsed.content[platform],
  };

  const sanitized = sanitizeEpisodePayload(
    {
      strategyNote: currentPayload.strategyNote,
      agentReasoning:
        parsed.agentReasoning ||
        `Regenerated ${platformLabel} based on feedback: ${feedback}`,
      content: mergedContent,
    },
    currentPayload.platforms,
    business.visualStyle || "clean, professional"
  );

  return {
    payload: sanitized,
    model: result.model,
    usage: result.usage,
  };
}
